import numpy as np

class TfidfVectorizer:
    def fit(self, documents: list) -> 'TfidfVectorizer':
        tokenized = [doc.lower().split() for doc in documents]
        vocab = sorted(set(t for tokens in tokenized for t in tokens))
        self.vocab_ = vocab
        self.word_to_idx_ = {w: i for i, w in enumerate(vocab)}
        n_docs = len(documents)

        df = np.zeros(len(vocab))
        for tokens in tokenized:
            for t in set(tokens):
                if t in self.word_to_idx_:
                    df[self.word_to_idx_[t]] += 1

        self.idf_ = np.log((1 + n_docs) / (1 + df)) + 1
        return self

    def transform(self, documents: list) -> np.ndarray:
        n_docs = len(documents)
        n_vocab = len(self.vocab_)
        X = np.zeros((n_docs, n_vocab))

        for i, doc in enumerate(documents):
            tokens = doc.lower().split()
            if not tokens:
                continue
            for t in tokens:
                if t in self.word_to_idx_:
                    X[i, self.word_to_idx_[t]] += 1
            X[i] /= len(tokens)  # TF

        X *= self.idf_  # TF-IDF
        return X

    def fit_transform(self, documents: list) -> np.ndarray:
        return self.fit(documents).transform(documents)
